## Cursor-Based Pagination Implementation

```javascript
// ─── Cursor Helpers ──────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * @param {Date|string} created_at
 * @param {number} id
 * @returns {string} base64-encoded cursor
 */
function encodeCursor(created_at, id) {
    const payload = JSON.stringify({
        // Normalize to ISO string so round-trips are stable regardless of
        // whether the DB driver returns a Date object or a string.
        created_at: new Date(created_at).toISOString(),
        id,
    });
    return Buffer.from(payload).toString('base64url'); // URL-safe, no padding issues
}

/**
 * Decodes a base64 cursor back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or structurally invalid.
 * @param {string} cursorStr
 * @returns {{ created_at: string, id: number } | null}
 */
function decodeCursor(cursorStr) {
    try {
        const payload = Buffer.from(cursorStr, 'base64url').toString('utf8');
        const parsed = JSON.parse(payload);

        // Structural validation — both fields must be present and the right type.
        if (
            typeof parsed.id !== 'number' ||
            !Number.isInteger(parsed.id) ||
            typeof parsed.created_at !== 'string' ||
            isNaN(Date.parse(parsed.created_at)) // valid ISO timestamp?
        ) {
            return null;
        }

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        // JSON.parse threw, Buffer.from threw, etc.
        return null;
    }
}

// ─── Route Handler ────────────────────────────────────────────────────────────

/**
 * GET /api/posts?limit=20&after=<cursor>
 *
 * Returns a page of published posts ordered by (created_at DESC, id DESC).
 * Pass the returned `nextCursor` as `after` to fetch the next page.
 */
async function getPosts(req, res) {
    // Clamp limit to a safe maximum so clients can't request 10 000 rows.
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterParam = req.query.after;

    // ── Decode cursor (if present) ──────────────────────────────────────────
    let cursor = null;
    if (afterParam !== undefined) {
        cursor = decodeCursor(afterParam);
        if (!cursor) {
            return res.status(400).json({
                error: 'Invalid cursor. Re-request the first page and paginate from there.',
            });
        }
    }

    // ── Build & execute query ───────────────────────────────────────────────
    // Fetch limit + 1 rows. If we get the extra row, there IS a next page.
    // We never use OFFSET; the WHERE clause picks up exactly where we left off.
    let result;

    if (cursor) {
        // Compound seek predicate mirrors the (created_at DESC, id DESC) sort:
        //   (created_at, id) < (cursor.created_at, cursor.id)
        // Expanded form is required here because the comparison direction is
        // DESC (not the default ASC that the row-value shorthand implies).
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (
                        created_at < $1
                     OR (created_at = $1 AND id < $2)
                    )
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursor.created_at, cursor.id, limit + 1],
        );
    } else {
        // No cursor → first page; no seek predicate needed.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1],
        );
    }

    // ── Apply N+1 trick ─────────────────────────────────────────────────────
    const rows    = result.rows;
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows; // drop the sentinel row

    // Build the next cursor from the LAST row of the page we're returning,
    // not from the sentinel row.
    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1].created_at, posts[posts.length - 1].id)
        : null;

    // ── Respond ─────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,  // null on the final page
            limit,
        },
    });
}
```

---

## Why cursor-based pagination is superior here

| Concern | Offset-based | Cursor-based |
|---|---|---|
| **Consistency under writes** | New posts shift rows, causing duplicates or skipped items between pages | Cursor anchors to a specific row; inserts/deletes before it have no effect |
| **Performance at depth** | `OFFSET 10000` forces the DB to scan and discard 10 000 rows every time | Seek predicate (`created_at < $1 OR …`) uses the index directly — O(log n) regardless of page number |
| **Expensive COUNT** | Requires `SELECT COUNT(*)` over the whole table (full index scan) | Eliminated entirely; `hasMore` is derived for free from the N+1 trick |
| **Stable sort required** | Not enforced — ties in sort key produce non-deterministic ordering | Compound `(created_at, id)` key is always unique, so ordering is perfectly stable |

The only trade-off is that clients lose the ability to jump to an arbitrary page number (e.g. "go to page 47"), but for an infinite-scroll or "load more" feed — the primary use case here — that's not a meaningful loss.

